 class ImageLoader
 {
     void LoadImage(PictureBox pictureBox, string url)
     {
         // .NET 9: PictureBox now throws HttpRequestException/TaskCanceledException instead of WebException.
         try { pictureBox.Load(url); }
         catch (HttpRequestException ex) { Console.WriteLine("Failed: " + ex.Message); }
         catch (TaskCanceledException ex) { Console.WriteLine("Timeout: " + ex.Message); }
     }
 }

